/* ---------- Cost Scenarios ---------- */
function costScenarios(city, mult, cd) {
  const budget = { label: "Targeted crack and drainage fix", total: Math.round(2400 * mult / 100) * 100 };
  const mid = { label: "8-pier stabilization with engineering", total: Math.round(13500 * mult / 100) * 100 };
  const prem = { label: "Full stabilization and drainage overhaul", total: Math.round(26000 * mult / 100) * 100 };

  const budgetBody = `${cd.drainagePara.split(". ")[0]}. ${cd.moistureManagementPara.split(". ")[0]}.`;
  const midBody = `${cd.repairMethodPara.split(". ")[0]}. ${cd.permitAndEngineeringPara.split(". ")[0]}.`;
  const premBody = `${cd.pieringAlternativesPara.split(". ")[0]}. ${cd.warrantyCulturePara.split(". ")[0]}.`;

  function card(label, title, total, body, color) {
    return `
<div class="fp-scenario-card" style="border-top:4px solid ${color};">
<h3>${label}</h3>
<p class="fp-scenario-material">${title}</p>
<p class="fp-scenario-total">${fmtK(total)}</p>
<p class="fp-scenario-detail">${body}</p>
</div>`;
  }

  return `
<section class="section fp-section">
<h2>${city} Foundation Project Scenarios</h2>
<div class="fp-scenario-grid">
${card("Budget", budget.label, budget.total, budgetBody, "#22c55e")}
${card("Mid-range", mid.label, mid.total, midBody, "#3b82f6")}
${card("Premium", prem.label, prem.total, premBody, "#8b5cf6")}
</div>
</section>`;
}

